class Solution:
    def findNumberOfLIS(self, nums: List[int]) -> int:
        n=len(nums); ln=[1]*n; cnt=[1]*n
        for i in range(n):
            for j in range(i):
                if nums[j]<nums[i]:
                    if ln[j]+1>ln[i]: ln[i]=ln[j]+1; cnt[i]=cnt[j]
                    elif ln[j]+1==ln[i]: cnt[i]+=cnt[j]
        mx=max(ln); return sum(c for l,c in zip(ln,cnt) if l==mx)

